/* ── Chat Widget ──────────────────────────────────────── */
(function(){
var API_BASE='https://api-bscan.balancewises.io';var chatOpen=false;var chatHistory=[];var currentScanId=null;
function getScanId(){if(window._lastScanId)return window._lastScanId;var params=new URLSearchParams(location.search);if(params.get('challenge'))return params.get('challenge');return null;}
window.toggleChat=function(){chatOpen=!chatOpen;document.getElementById('chat-window').style.display=chatOpen?'block':'none';document.getElementById('chat-btn-icon').textContent=chatOpen?'✕':'💬';document.getElementById('chat-unread').style.display='none';if(window.innerWidth<=768)document.body.style.overflow=chatOpen?'hidden':'';if(chatOpen){document.getElementById('chat-input').focus();currentScanId=getScanId();}};
window.sendQuick=function(text){document.getElementById('chat-quick').style.display='none';document.getElementById('chat-input').value=text;sendChat();};
window.sendChat=function(){var input=document.getElementById('chat-input');var text=input.value.trim();if(!text)return;input.value='';var msgs=document.getElementById('chat-messages');var userDiv=document.createElement('div');userDiv.className='chat-msg user';userDiv.innerHTML='<div style="max-width:85%;background:#3b82f6;border-radius:12px 12px 4px 12px;padding:10px 14px;margin-left:auto;"><div style="font-size:13px;color:#fff;line-height:1.5;">'+escHtml(text)+'</div></div>';msgs.appendChild(userDiv);var typingDiv=document.createElement('div');typingDiv.className='chat-msg bot';typingDiv.id='chat-typing';typingDiv.innerHTML='<div style="max-width:85%;background:#141d33;border:1px solid #1e2d4a;border-radius:12px 12px 12px 4px;padding:12px 14px;"><div style="display:flex;gap:4px;align-items:center;"><span style="width:6px;height:6px;border-radius:50%;background:#64748b;animation:pulse 1s infinite;"></span><span style="width:6px;height:6px;border-radius:50%;background:#64748b;animation:pulse 1s infinite .2s;"></span><span style="width:6px;height:6px;border-radius:50%;background:#64748b;animation:pulse 1s infinite .4s;"></span></div></div>';msgs.appendChild(typingDiv);msgs.scrollTop=msgs.scrollHeight;chatHistory.push({role:'user',content:text});fetch(API_BASE+'/api/scan/chat',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({message:text,scan_id:currentScanId||getScanId(),conversation_history:chatHistory.slice(-10)})}).then(function(r){return r.json();}).then(function(d){var typing=document.getElementById('chat-typing');if(typing)typing.remove();var reply=d.reply||'Sorry, I could not generate a response.';chatHistory.push({role:'assistant',content:reply});var botDiv=document.createElement('div');botDiv.className='chat-msg bot';botDiv.innerHTML='<div style="max-width:85%;background:#141d33;border:1px solid #1e2d4a;border-radius:12px 12px 12px 4px;padding:12px 14px;"><div style="font-size:13px;color:#e2e8f0;line-height:1.6;">'+escHtml(reply)+'</div></div>';msgs.appendChild(botDiv);msgs.scrollTop=msgs.scrollHeight;if(d.scan_id)currentScanId=d.scan_id;}).catch(function(){var typing=document.getElementById('chat-typing');if(typing)typing.remove();var errDiv=document.createElement('div');errDiv.className='chat-msg bot';errDiv.innerHTML='<div style="max-width:85%;background:#141d33;border:1px solid rgba(239,68,68,.2);border-radius:12px 12px 12px 4px;padding:12px 14px;"><div style="font-size:13px;color:#ef4444;line-height:1.5;">Connection error. Please try again.</div></div>';msgs.appendChild(errDiv);msgs.scrollTop=msgs.scrollHeight;});};
function escHtml(t){return t.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>');}
setTimeout(function(){if(!chatOpen)document.getElementById('chat-unread').style.display='flex';},8000);
})();

/* ── Main Scan Logic ──────────────────────────────────── */
var API='https://api-bscan.balancewises.io';
var PRICING={pro:{monthly:9,annual:7},agency:{monthly:29,annual:23}};
var currentInterval='monthly',checkoutPlan='',pendingUrl='';
var capturedEmail=localStorage.getItem('bscan_email')||'',capturedName=localStorage.getItem('bscan_name')||'';
if(!localStorage.getItem('bscan_token')){capturedEmail='';capturedName='';}
var lastCheckResult=null;

function setBillingInterval(i){currentInterval=i;document.getElementById('tog-m').style.background=i==='monthly'?'var(--accent-blue)':'transparent';document.getElementById('tog-m').style.color=i==='monthly'?'#fff':'var(--text-secondary)';document.getElementById('tog-a').style.background=i==='annual'?'var(--accent-blue)':'transparent';document.getElementById('tog-a').style.color=i==='annual'?'#fff':'var(--text-secondary)';document.querySelectorAll('.price-monthly').forEach(function(el){el.style.display=i==='monthly'?'inline':'none';});document.querySelectorAll('.price-annual').forEach(function(el){el.style.display=i==='annual'?'inline':'none';});document.querySelectorAll('.plan-period').forEach(function(el){if(el.closest('.plan-free'))return;el.textContent=i==='annual'?'per month (billed annually)':'per month';});}
function startStripeCheckout(plan){checkoutPlan=plan;var ia=currentInterval==='annual',pr=PRICING[plan]?PRICING[plan][currentInterval]:'?',pn=plan.charAt(0).toUpperCase()+plan.slice(1);document.getElementById('checkout-plan-name').textContent=pn;document.getElementById('checkout-plan-tag').textContent=pn+' · '+(ia?'Annual':'Monthly');document.getElementById('checkout-plan-tag').className='checkout-plan-tag '+plan;document.getElementById('checkout-sub').textContent='£'+pr+'/'+(ia?'mo (billed annually)':'mo')+' — enter your email to continue to secure checkout.';var b=document.getElementById('checkout-submit-btn');b.className=plan==='pro'?'checkout-submit gold':'checkout-submit blue';b.innerHTML='Continue to Checkout →';b.disabled=false;var ei=document.getElementById('checkout-email');ei.value=localStorage.getItem('bscan_email')||'';ei.classList.remove('error');document.getElementById('checkout-email-error').classList.remove('active');document.getElementById('checkout-overlay').classList.add('active');setTimeout(function(){ei.focus();},100);}
function closeCheckoutModal(){document.getElementById('checkout-overlay').classList.remove('active');}
document.getElementById('checkout-email').addEventListener('keydown',function(e){if(e.key==='Enter')submitCheckout();e.target.classList.remove('error');document.getElementById('checkout-email-error').classList.remove('active');});
async function submitCheckout(){var ei=document.getElementById('checkout-email'),em=ei.value.trim(),er=document.getElementById('checkout-email-error'),b=document.getElementById('checkout-submit-btn');if(!em||!em.includes('@')||!em.includes('.')){ei.classList.add('error');er.classList.add('active');ei.focus();return;}b.disabled=true;b.innerHTML='<div class="spinner"></div> Redirecting to Stripe...';localStorage.setItem('bscan_email',em);try{var r=await fetch(API+'/api/billing/checkout/'+checkoutPlan,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email:em,interval:currentInterval})});var d=await r.json();if(d.checkout_url)window.location=d.checkout_url;else{b.disabled=false;b.innerHTML='Continue to Checkout →';er.textContent=d.detail||'Could not start checkout.';er.classList.add('active');}}catch(e){b.disabled=false;b.innerHTML='Continue to Checkout →';er.textContent='Network error.';er.classList.add('active');}}
document.addEventListener('keydown',function(e){if(e.key==='Escape')closeCheckoutModal();});
function updateScanCount(){var el=document.getElementById('scan-count');if(lastCheckResult){var r=lastCheckResult.scans_remaining,plan=lastCheckResult.plan;if(plan==='guest'||plan==='free'){if(r<=0)el.innerHTML='<strong style="color:var(--danger)">0</strong> free scans remaining — <a href="#" onclick="showPaywall();return false" style="color:var(--accent-gold)">upgrade for unlimited</a>';else el.innerHTML='<strong>'+r+'</strong> free scan'+(r!==1?'s':'')+' remaining';}else el.innerHTML='<strong style="color:var(--success)">'+plan.toUpperCase()+'</strong> plan · '+(r>100?'unlimited':r+' scans left');}}
function showPaywall(title,msg){if(title)document.getElementById('paywall-title').textContent=title;if(msg)document.getElementById('paywall-msg').textContent=msg;document.getElementById('paywall').classList.add('active');}
function closePaywall(){document.getElementById('paywall').classList.remove('active');}
function setUrl(u){document.getElementById('url-input').value=u;document.getElementById('url-input').focus();}
document.getElementById('url-input').addEventListener('keydown',function(e){if(e.key==='Enter')startAudit();});
function startAudit(){var u=document.getElementById('url-input').value.trim();if(!u)return document.getElementById('url-input').focus();if(!u.startsWith('http'))u='https://'+u;pendingUrl=u;if(capturedEmail){document.getElementById('lead-email').value=capturedEmail;document.getElementById('lead-name').value=capturedName;submitGateAndScan();return;}document.getElementById('gate-url-preview').textContent='Scanning: '+u.replace('https://','').replace('http://','').split('/')[0];document.getElementById('email-gate').classList.add('active');document.getElementById('lead-email').focus();}
async function submitGateAndScan(){var email=document.getElementById('lead-email').value.trim(),name=document.getElementById('lead-name').value.trim();if(!email||!email.includes('@')||!email.includes('.')){document.getElementById('lead-email').style.borderColor='var(--danger)';document.getElementById('lead-email').focus();return;}document.getElementById('lead-email').style.borderColor='';capturedEmail=email;capturedName=name;localStorage.setItem('bscan_email',email);localStorage.setItem('bscan_name',name);var gateBtn=document.getElementById('gate-submit');gateBtn.disabled=true;gateBtn.innerHTML='<div class="spinner"></div> Checking...';try{var cr=await fetch(API+'/api/scan/check',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email:email})});var check=await cr.json();lastCheckResult=check;updateScanCount();if(!check.can_scan){gateBtn.disabled=false;gateBtn.innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/></svg>Start Free Audit';document.getElementById('email-gate').classList.remove('active');showPaywall(check.has_account?'Scan limit reached':"You've used your 3 free scans",check.message||'Create an account and upgrade to Pro for 30 scans/month.');return;}document.getElementById('email-gate').classList.remove('active');gateBtn.disabled=false;gateBtn.innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/></svg>Start Free Audit';runScan(pendingUrl,email,name,check);}catch(e){gateBtn.disabled=false;gateBtn.innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/></svg>Start Free Audit';document.getElementById('email-gate').classList.remove('active');runScan(pendingUrl,email,name,null);}}
document.getElementById('lead-email').addEventListener('keydown',function(e){if(e.key==='Enter')submitGateAndScan();});
document.getElementById('lead-name').addEventListener('keydown',function(e){if(e.key==='Enter')submitGateAndScan();});
async function runScan(url,email,biz,checkResult){var btn=document.getElementById('audit-btn');btn.classList.add('scanning');btn.innerHTML='<div class="spinner"></div> Scanning...';document.getElementById('results').classList.remove('active');var t=document.getElementById('terminal'),w=document.getElementById('terminal-wrap'),b=document.getElementById('progress-fill');t.innerHTML='';w.classList.add('active');b.style.width='0%';var isPaid=checkResult&&(checkResult.plan==='pro'||checkResult.plan==='agency');var steps=isPaid?[{t:'Initialising BSCAN engine...',p:3},{t:'Resolving '+url+'...',p:6},{t:'Rendering page via Cloudflare...',p:10},{t:'Verifying SSL certificate...',p:14},{t:'Fetching page content...',p:18},{t:'Detecting technology stack...',p:22},{t:'Scanning meta tags & Open Graph...',p:26},{t:'Analysing heading hierarchy...',p:30},{t:'Crawling links for broken URLs...',p:34},{t:'Auditing image alt text...',p:38},{t:'Checking form labels & ARIA...',p:42},{t:'Scanning for exposed API keys...',p:46},{t:'Connecting to Google Lighthouse...',p:50},{t:'Running Core Web Vitals audit...',p:55},{t:'Measuring Largest Contentful Paint...',p:60},{t:'Measuring Cumulative Layout Shift...',p:64},{t:'Measuring Total Blocking Time...',p:68},{t:'Checking server location & hosting...',p:72},{t:'Validating HTML (W3C)...',p:76},{t:'Checking domain WHOIS...',p:80},{t:'Verifying Google Safe Browsing...',p:84},{t:'Checking green hosting status...',p:88},{t:'Scoring accessibility compliance...',p:91},{t:'Scoring SEO signals...',p:94},{t:'Compiling final report...',p:97}]:[{t:'Initialising BSCAN...',p:5},{t:'Resolving '+url+'...',p:12},{t:'Checking SSL certificate...',p:22},{t:'Fetching page content...',p:34},{t:'Detecting technology stack...',p:44},{t:'Scanning meta tags...',p:54},{t:'Analysing heading hierarchy...',p:62},{t:'Crawling links...',p:70},{t:'Auditing images & accessibility...',p:78},{t:'Scanning security & exposed keys...',p:86},{t:'Checking server & hosting...',p:92},{t:'Compiling report...',p:97}];var interval=isPaid?500:400;var li=0;var iv=setInterval(function(){if(li>=steps.length){clearInterval(iv);return;}addLine(t,li+1,steps[li].t,'ok');b.style.width=steps[li].p+'%';li++;},interval);try{var headers={'Content-Type':'application/json'};var token=localStorage.getItem('bscan_token');if(token)headers['Authorization']='Bearer '+token;var r=await fetch(API+'/api/scan',{method:'POST',headers:headers,body:JSON.stringify({url:url,email:email,business_name:biz})});clearInterval(iv);if(!r.ok){var e=await r.json().catch(function(){return{};});throw new Error(e.detail||'Server error ('+r.status+')');}var d=await r.json();while(li<steps.length){addLine(t,li+1,steps[li].t,'ok');li++;}addLine(t,li+1,'Report generated ✓','ok');b.style.width='100%';if(lastCheckResult){lastCheckResult.scans_used++;lastCheckResult.scans_remaining=Math.max(0,lastCheckResult.scans_remaining-1);updateScanCount();}setTimeout(function(){showResults(url,d,checkResult);},600);}catch(err){clearInterval(iv);addLine(t,li+1,'Error: '+err.message,'fail');b.style.width='100%';setTimeout(function(){btn.classList.remove('scanning');btn.innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/></svg> BSCAN It';},1500);}}
function addLine(t,n,x,s){var l=document.createElement('div');l.className='t-line';var c=s==='ok'?'t-ok':s==='warn'?'t-warn':'t-fail',i=s==='ok'?'✓':s==='warn'?'⚠':'✗';l.innerHTML='<span class="t-prefix">['+String(n).padStart(2,'0')+']</span> <span class="t-text">'+x+'</span> <span class="'+c+'">'+i+'</span>';t.appendChild(l);t.scrollTop=t.scrollHeight;}
function buildIssue(it,gr,url,showFixBtn){var ct=it.category?it.category.charAt(0).toUpperCase()+it.category.slice(1):'';var f='';if(it.fix){f='<div class="issue-fix">Fix: '+it.fix+'</div>';if(showFixBtn)f+='<div style="display:flex;gap:8px;margin-top:8px;flex-wrap:wrap;"><a href="https://balancewises.io/#contact?issue='+encodeURIComponent(it.title)+'&url='+encodeURIComponent(url)+'" target="_blank" style="font-size:11px;padding:5px 12px;border-radius:6px;background:var(--accent-gold);color:var(--bg-deep);text-decoration:none;font-weight:700;">Get Balancewise to Fix →</a></div>';}return '<div class="issue-icon '+gr.type+'">'+gr.icon+'</div><div class="issue-body"><div class="issue-title">'+it.title+'</div><div class="issue-desc">'+it.description+'</div>'+f+'<span class="issue-tag">'+ct+'</span></div>';}

function renderEnrichment(e,isPaid){var box=document.getElementById('enrichment-box');box.innerHTML='';if(!e||!Object.keys(e).length)return;var tech=e.tech_stack||{},ssl=e.ssl_details||{},whois=e.whois||{},green=e.green_hosting||{},geo=e.server_location||{},safe=e.safe_browsing||{},obs=e.observatory||{},w3c=e.w3c_validation||{},wb=e.wayback||{},screenshot=e.screenshot_url||'';var h='';if(screenshot)h+='<div style="background:var(--bg-card);border:1px solid var(--border);border-radius:12px;overflow:hidden;margin-bottom:16px;"><div style="padding:14px 18px;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:8px;"><span style="font-size:14px">📸</span><span style="font-weight:700;font-size:13px">Site Preview</span></div><div style="padding:12px;text-align:center;background:var(--bg-primary)"><img src="'+screenshot+'" alt="Website Screenshot" style="max-width:100%;border-radius:6px;border:1px solid var(--border)" loading="lazy" onerror="this.parentElement.innerHTML=\'<div style=padding:20px;color:var(--text-muted);font-size:12px>Screenshot unavailable</div>\'"></div></div>';h+='<div style="background:var(--bg-card);border:1px solid var(--border);border-radius:12px;overflow:hidden;margin-bottom:16px;"><div style="padding:14px 18px;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:8px"><span style="font-size:14px">🔬</span><span style="font-weight:700;font-size:13px">Site Intelligence</span><span style="font-size:10px;color:var(--text-muted);margin-left:auto;font-family:Space Mono,monospace">ENRICHED ANALYSIS</span></div><div class="enrich-grid">';if(ssl.ssl_grade){var sc=ssl.ssl_grade==='A+'||ssl.ssl_grade==='A'?'var(--success)':ssl.ssl_grade==='B'?'var(--warning)':'var(--danger)';h+='<div class="enrich-cell"><div class="enrich-label">SSL Certificate</div><div class="enrich-val" style="font-size:24px;color:'+sc+'">'+ssl.ssl_grade+'</div><div class="enrich-sub">'+(ssl.ssl_issuer||'Unknown')+'</div>'+(ssl.ssl_days_remaining?'<div style="font-size:10px;color:var(--text-muted);margin-top:2px">'+ssl.ssl_days_remaining+' days until expiry</div>':'')+'</div>';}if(geo.server_country)h+='<div class="enrich-cell"><div class="enrich-label">Server Location</div><div class="enrich-val" style="color:var(--text-primary)">'+(geo.server_city?geo.server_city+', ':'')+geo.server_country+'</div><div class="enrich-sub">'+(geo.server_isp||'')+'</div>'+(geo.server_ip?'<div style="font-size:10px;color:var(--text-muted);font-family:Space Mono,monospace;margin-top:2px">'+geo.server_ip+'</div>':'')+'</div>';if(green.is_green!==null&&green.is_green!==undefined){var gi=green.is_green?'🌱':'⚫',gt=green.is_green?'Green Hosted':'Standard Hosting',gc=green.is_green?'var(--success)':'var(--text-muted)';h+='<div class="enrich-cell"><div class="enrich-label">Green Energy</div><div class="enrich-val" style="color:'+gc+'">'+gi+' '+gt+'</div>'+(green.green_hosting_provider?'<div class="enrich-sub">'+green.green_hosting_provider+'</div>':'')+'</div>';}if(safe.safe_browsing_status&&safe.safe_browsing_status!=='not_checked'){var si=safe.is_safe?'✓ Safe':'⚠ Flagged',sc2=safe.is_safe?'var(--success)':'var(--danger)';h+='<div class="enrich-cell"><div class="enrich-label">Google Safe Browsing</div><div class="enrich-val" style="color:'+sc2+'">'+si+'</div><div class="enrich-sub">Checked against Google threat database</div></div>';}if(whois.domain_age_text){var ac=whois.is_new_domain?'var(--warning)':'var(--success)';h+='<div class="enrich-cell"><div class="enrich-label">Domain Age</div><div class="enrich-val" style="color:'+ac+'">'+whois.domain_age_text+'</div>'+(whois.registrar?'<div class="enrich-sub">Registrar: '+whois.registrar+'</div>':'')+(whois.expiry_date?'<div style="font-size:10px;color:var(--text-muted);margin-top:2px">Expires: '+whois.expiry_date+'</div>':'')+'</div>';}if(obs.observatory_grade){var oc=obs.observatory_grade.startsWith('A')?'var(--success)':obs.observatory_grade.startsWith('B')?'var(--info)':obs.observatory_grade.startsWith('C')?'var(--warning)':'var(--danger)';h+='<div class="enrich-cell"><div class="enrich-label">Mozilla Observatory</div><div class="enrich-val" style="font-size:24px;color:'+oc+'">'+obs.observatory_grade+'</div><div class="enrich-sub">'+(obs.observatory_score||0)+'/100 · '+(obs.observatory_tests_passed||0)+' passed</div></div>';}if(w3c.html_valid!==null&&w3c.html_valid!==undefined){var wc=w3c.html_valid?'var(--success)':w3c.html_errors>10?'var(--danger)':'var(--warning)',wt=w3c.html_valid?'Valid HTML':w3c.html_errors+' errors';h+='<div class="enrich-cell"><div class="enrich-label">W3C Validation</div><div class="enrich-val" style="color:'+wc+'">'+wt+'</div><div class="enrich-sub">'+(w3c.html_warnings||0)+' warnings</div></div>';}if(wb.has_archive)h+='<div class="enrich-cell"><div class="enrich-label">Web Archive</div><div class="enrich-val" style="color:var(--info)">Archived</div>'+(wb.first_archived?'<div class="enrich-sub">First seen: '+wb.first_archived+'</div>':'')+(wb.wayback_url?'<div style="margin-top:4px"><a href="'+wb.wayback_url+'" target="_blank" style="font-size:10px;color:var(--accent-blue);text-decoration:none">View on Wayback Machine →</a></div>':'')+'</div>';h+='</div></div>';if(tech.technologies&&tech.technologies.length>0){h+='<div style="background:var(--bg-card);border:1px solid var(--border);border-radius:12px;overflow:hidden;margin-bottom:16px;"><div style="padding:14px 18px;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:8px"><span style="font-size:14px">⚙️</span><span style="font-weight:700;font-size:13px">Technology Stack</span><span style="font-size:10px;color:var(--text-muted);margin-left:auto">'+tech.tech_count+' detected</span></div><div style="padding:14px 18px;display:flex;flex-wrap:wrap;gap:6px">';var cats=tech.categories||{};tech.technologies.forEach(function(t){var tc='var(--text-secondary)',tb='var(--bg-primary)';if(t===cats.cms){tc='var(--accent-gold)';tb='rgba(245,166,35,.1)';}else if(t===cats.js_framework){tc='var(--accent-blue)';tb='rgba(59,130,246,.1)';}else if(t===cats.server||t===cats.cdn){tc='var(--success)';tb='rgba(34,197,94,.1)';}else if(t===cats.ecommerce){tc='#8b5cf6';tb='rgba(139,92,246,.1)';}h+='<span class="tech-tag" style="background:'+tb+';color:'+tc+';border:1px solid '+tc+'20">'+t+'</span>';});h+='</div>';var ci=[];if(cats.cms)ci.push('CMS: '+cats.cms);if(cats.js_framework)ci.push('Framework: '+cats.js_framework);if(cats.server)ci.push('Server: '+cats.server);if(cats.cdn)ci.push('CDN: '+cats.cdn);if(cats.ecommerce)ci.push('E-commerce: '+cats.ecommerce);if(cats.analytics)ci.push('Analytics: '+cats.analytics);if(ci.length)h+='<div style="padding:10px 18px;border-top:1px solid var(--border);font-size:11px;color:var(--text-muted)">'+ci.join(' · ')+'</div>';h+='</div>';}if(!isPaid&&tech.technologies&&tech.technologies.length>0){h+='<div style="background:var(--bg-card);border:2px dashed var(--border-light);border-radius:14px;padding:24px;text-align:center;margin-bottom:16px;"><div style="font-size:24px;margin-bottom:8px">🔬</div><h3 style="font-size:14px;font-weight:700;color:var(--text-primary);margin-bottom:4px">Full Site Intelligence</h3><p style="font-size:12px;color:var(--text-secondary);line-height:1.6;max-width:380px;margin:0 auto 12px">Upgrade to Pro to unlock domain age, WHOIS data, W3C validation, Mozilla Observatory score, Wayback history, and more.</p><a href="/#pricing" style="display:inline-block;padding:8px 20px;background:var(--accent-gold);color:var(--bg-deep);border-radius:8px;font-weight:700;font-size:12px;text-decoration:none">Upgrade to Pro — £9/mo</a></div>';}box.innerHTML=h;}

/* ── Score Cards ──────────────────────────────────────── */
function renderScoreCards(gridEl,scores,scanData,isPaid,scannedUrl){gridEl.innerHTML='';var categories=[{key:'seo',label:'SEO',icon:'🔍',getMini:function(issues){var si=issues.filter(function(i){return i.category==='seo';});var cr=si.filter(function(i){return i.severity==='critical';}).length;var wa=si.filter(function(i){return i.severity==='warning';}).length;var pa=si.filter(function(i){return i.severity==='pass';}).length;return[{label:'Critical',val:cr,cls:cr>0?'bad':'good'},{label:'Warnings',val:wa,cls:wa>0?'warn':'good'},{label:'Passed',val:pa,cls:'good'}];}},{key:'performance',label:'Performance',icon:'⚡',getMini:function(issues){var pi=issues.filter(function(i){return i.category==='performance';});return[{label:'Critical',val:pi.filter(function(i){return i.severity==='critical';}).length,cls:pi.filter(function(i){return i.severity==='critical';}).length>0?'bad':'good'},{label:'Warnings',val:pi.filter(function(i){return i.severity==='warning';}).length,cls:pi.filter(function(i){return i.severity==='warning';}).length>0?'warn':'good'}];}},{key:'accessibility',label:'Accessibility',icon:'♿',getMini:function(issues){var a=issues.filter(function(i){return i.category==='accessibility';});return[{label:'Issues',val:a.filter(function(i){return i.severity==='critical';}).length,cls:a.filter(function(i){return i.severity==='critical';}).length>0?'bad':'good'},{label:'Passed',val:a.filter(function(i){return i.severity==='pass';}).length,cls:'good'}];}},{key:'security',label:'Security',icon:'🔒',getMini:function(issues,enrichment){var si=issues.filter(function(i){return i.category==='security';});var cr=si.filter(function(i){return i.severity==='critical';}).length;var ssl=(enrichment&&enrichment.ssl_details)?enrichment.ssl_details.ssl_grade:null;var stats=[{label:'Critical',val:cr,cls:cr>0?'bad':'good'}];if(ssl)stats.push({label:'SSL Grade',val:ssl,cls:ssl==='A+'||ssl==='A'?'good':'warn'});return stats;}},{key:'mobile',label:'Mobile',icon:'📱',getMini:function(issues){var m=issues.filter(function(i){return i.category==='mobile';});return[{label:'Issues',val:m.filter(function(i){return i.severity==='critical';}).length,cls:m.filter(function(i){return i.severity==='critical';}).length>0?'bad':'good'},{label:'Passed',val:m.filter(function(i){return i.severity==='pass';}).length,cls:'good'}];}},{key:'links',label:'Links',icon:'🔗',getMini:function(issues){var l=issues.filter(function(i){return i.category==='links';});return[{label:'Broken',val:l.filter(function(i){return i.severity==='critical';}).length,cls:l.filter(function(i){return i.severity==='critical';}).length>0?'bad':'good'},{label:'Healthy',val:l.filter(function(i){return i.severity==='pass';}).length,cls:'good'}];}}];var issues=scanData.issues||[];var enrichment=scanData.enrichment||{};categories.forEach(function(cat){var score=scores[cat.key]||0;var level=score>=80?'excellent':score>=60?'good':score>=40?'warning':'poor';var levelText=score>=80?'Excellent':score>=60?'Good':score>=40?'Warning':'Poor';var miniStats=cat.getMini(issues,enrichment);var card=document.createElement('div');card.className='s-card '+level;card.onclick=function(){toggleDetail(cat.key,score,level,cat.label,cat.icon,issues,enrichment,isPaid,scannedUrl);};var miniHtml='<div class="s-mini">';miniStats.forEach(function(s){miniHtml+='<div class="s-mini-stat"><span>'+s.label+'</span><span class="val '+s.cls+'">'+s.val+'</span></div>';});miniHtml+='</div>';card.innerHTML='<div class="s-num">'+score+'</div><div class="s-label">'+cat.label+'</div><div class="s-tag">'+levelText+'</div>'+miniHtml+'<div class="s-tap">tap for details →</div>';gridEl.appendChild(card);});var featureCards=[{key:'business_intel',icon:'💼',label:'Business Intel',free:false,getData:function(){var bi=scanData.business_intel||{};var ct=bi.ctas?bi.ctas.total_ctas||0:0;var pay=bi.payment_methods?bi.payment_methods.methods||[]:[];var soc=bi.social_media?bi.social_media.count||0:0;return{count:ct+pay.length+soc,sub:'CTAs, payments, social'};}},{key:'consumer_intel',icon:'🛍️',label:'Consumer Intel',free:false,getData:function(){var ci=scanData.consumer_intel||{};var tr=ci.trust_signals?ci.trust_signals.count||0:0;var su=ci.customer_support?ci.customer_support.score||0:0;return{count:tr,sub:'Trust: '+tr+' · Support: '+su+'/100'};}},{key:'ux_patterns',icon:'🎨',label:'UX Patterns',free:false,getData:function(){var bench=scanData.benchmarks||{};var ux=bench.ux_patterns||{};return{count:ux.total_detected||0,sub:(ux.ux_score||0)+'/100 UX score'};}},{key:'keywords',icon:'🔍',label:'Keywords',free:true,getData:function(){var bi=scanData.business_intel||{};var kw=bi.keywords||{};var top=kw.top_words||[];return{count:top.length,sub:top.slice(0,3).join(', ')||'Run scan first'};}},{key:'benchmarks',icon:'📊',label:'Industry Rank',free:false,getData:function(){var bench=scanData.benchmarks||{};var ind=bench.industry||{};return{count:ind.detected_industry?1:0,sub:ind.industry_label||'Not detected'};}}];featureCards.forEach(function(feat){var data=feat.getData();var isLocked=!isPaid&&!feat.free;var card=document.createElement('div');card.className='s-card feature-card'+(isLocked?' locked':'');card.onclick=function(){if(isLocked)toggleFeatureDetail(feat.key,feat.label,feat.icon,true);else toggleFeatureDetail(feat.key,feat.label,feat.icon,false,scanData);};card.innerHTML='<div class="s-icon">'+feat.icon+'</div><div class="s-num" style="font-size:24px;">'+(data.count||'—')+'</div><div class="s-label">'+feat.label+'</div>'+(data.sub?'<div class="s-mini" style="border-top:none;text-align:center;padding-top:4px;">'+escH(data.sub)+'</div>':'')+(isLocked?'<div class="s-lock">🔒 Pro</div>':'<div class="s-tap">tap for details →</div>');gridEl.appendChild(card);});}

function escH(t){return(t||'').toString().replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}

