function toggleFeatureDetail(key,label,icon,isLocked,scanData){var panelId='detail-'+key;var existing=document.getElementById(panelId);if(existing){existing.remove();return;}document.querySelectorAll('.detail-panel').forEach(function(p){p.remove();});var panel=document.createElement('div');panel.className='detail-panel active';panel.id=panelId;var html='<div class="detail-header"><div class="detail-header-left"><div style="font-size:28px;">'+icon+'</div><div><div class="detail-title">'+label+'</div><div class="detail-subtitle">'+(isLocked?'Pro/Agency feature':'Included in your plan')+'</div></div></div><button class="detail-close" onclick="document.getElementById(\''+panelId+'\').remove()">Close ✕</button></div><div class="detail-body">';if(isLocked){var fd={'business_intel':{title:'Business Intelligence',desc:'See exactly how this website drives revenue: payment methods, CTAs, email capture, urgency tactics, social proof, live chat, and conversion tools.',features:['Payment Methods','CTA Detection','Email Capture','Urgency Tactics','Social Proof','Live Chat','Conversion Tools']},'consumer_intel':{title:'Consumer Intelligence',desc:'Understand the customer experience: reviews, support channels, trust signals, loyalty programs, delivery options, pricing psychology, and personalization.',features:['Reviews & Ratings','Customer Support Score','Trust Signals','Loyalty Programs','Pricing Psychology','Delivery Options','Personalization']},'ux_patterns':{title:'UX Pattern Detection',desc:'30+ UX patterns detected across navigation, product pages, conversion, mobile, content, and trust categories.',features:['Navigation','Product Page','Conversion','Mobile UX','Content','Trust Elements']},'benchmarks':{title:'Industry Benchmarking',desc:'See how this site ranks against others in its industry. Percentile scores, industry averages, and specific recommendations.',features:['Industry Detection','Percentile Ranking','Score Comparison','Recommendations']}};var info=fd[key]||{title:label,desc:'Detailed analysis available with upgrade.',features:[]};html+='<div class="detail-upgrade"><div style="font-size:32px;margin-bottom:10px;">'+icon+'</div><h3 style="font-size:16px;font-weight:700;margin-bottom:6px;">'+info.title+'</h3><p>'+info.desc+'</p>';if(info.features.length){html+='<div style="display:flex;flex-wrap:wrap;gap:6px;justify-content:center;margin-bottom:16px;">';info.features.forEach(function(f){html+='<span style="font-size:10px;padding:4px 10px;border-radius:100px;background:rgba(6,182,212,.08);border:1px solid rgba(6,182,212,.15);color:#06b6d4;">'+f+'</span>';});html+='</div>';}html+='<a class="detail-upgrade-btn" href="/#pricing">Upgrade to Pro — £9/mo</a></div>';}else{if(key==='business_intel'&&scanData)html+=renderBusinessIntelDetail(scanData.business_intel||{});else if(key==='consumer_intel'&&scanData)html+=renderConsumerIntelDetail(scanData.consumer_intel||{});else if(key==='ux_patterns'&&scanData)html+=renderUXDetail((scanData.benchmarks||{}).ux_patterns||{});else if(key==='keywords'&&scanData)html+=renderKeywordsDetail((scanData.business_intel||{}).keywords||{});else if(key==='benchmarks'&&scanData)html+=renderBenchmarkDetail((scanData.benchmarks||{}).industry||{});else html+='<div class="empty"><p>No data available for this scan.</p></div>';}html+='</div>';panel.innerHTML=html;var grid=document.getElementById('scores-grid');grid.parentNode.insertBefore(panel,grid.nextSibling);panel.scrollIntoView({behavior:'smooth',block:'nearest'});}

/* ── Feature Detail Renderers ─────────────────────────── */
function renderBusinessIntelDetail(bi){var h='';var sections=[{key:'ctas',icon:'🎯',title:'CTAs',render:function(d){return'Total: '+(d.total_ctas||0)+' · Purchase: '+((d.purchase_ctas||[]).length)+' · Signup: '+((d.signup_ctas||[]).length);}},{key:'payment_methods',icon:'💳',title:'Payment Methods',render:function(d){return(d.methods||[]).join(', ')||'None detected';}},{key:'social_proof',icon:'⭐',title:'Social Proof',render:function(d){return'Score: '+(d.score||0)+' · Signals: '+((d.signals||[]).join(', ')||'None');}},{key:'email_capture',icon:'✉️',title:'Email Capture',render:function(d){return(d.methods||[]).join(', ')||'None detected';}},{key:'urgency_tactics',icon:'⏰',title:'Urgency Tactics',render:function(d){return(d.tactics||[]).join(', ')||'None detected';}},{key:'social_media',icon:'📱',title:'Social Media',render:function(d){var p=d.platforms||{};return Object.keys(p).join(', ')||'None linked';}},{key:'live_chat',icon:'💬',title:'Live Chat',render:function(d){return d.has_live_chat?(d.tools||[]).join(', '):'Not detected';}},{key:'pricing',icon:'💰',title:'Pricing',render:function(d){return d.prices_found?d.prices_found+' prices · '+(d.currency||'')+' '+(d.price_range||''):'No prices found';}}];sections.forEach(function(s){var data=bi[s.key]||{};h+='<div class="detail-issue"><div style="font-size:16px;width:28px;text-align:center;flex-shrink:0;">'+s.icon+'</div><div class="detail-issue-text"><strong>'+s.title+'</strong><br>'+s.render(data)+'</div></div>';});return h;}

function renderConsumerIntelDetail(ci){var h='';var sections=[{key:'reviews_ratings',icon:'⭐',title:'Reviews',render:function(d){return d.has_reviews?'Found · Platforms: '+(d.review_platforms||[]).join(', ')+(d.star_rating?' · '+d.star_rating+' stars':''):'No reviews detected';}},{key:'customer_support',icon:'🎧',title:'Support',render:function(d){return'Score: '+(d.score||0)+'/100 · Channels: '+((d.channels||[]).join(', ')||'None');}},{key:'trust_signals',icon:'🛡️',title:'Trust Signals',render:function(d){return(d.count||0)+' found: '+((d.signals||[]).slice(0,4).join(', ')||'None');}},{key:'loyalty_program',icon:'🎁',title:'Loyalty',render:function(d){return d.has_loyalty_program?(d.program_type||[]).join(', '):'Not detected';}},{key:'pricing_psychology',icon:'💰',title:'Pricing Tactics',render:function(d){return(d.count||0)+' tactics · '+(d.sophistication||'None')+': '+((d.tactics||[]).slice(0,3).join(', '));}},{key:'delivery_shipping',icon:'🚚',title:'Delivery',render:function(d){return(d.signals||[]).join(', ')||'No delivery info detected';}},{key:'personalization',icon:'🎯',title:'Personalization',render:function(d){return(d.sophistication||'None')+': '+((d.features||[]).join(', ')||'None detected');}},{key:'return_policy',icon:'↩️',title:'Returns',render:function(d){return d.has_return_policy?(d.signals||[]).join(', '):'No return policy found';}}];sections.forEach(function(s){var data=ci[s.key]||{};h+='<div class="detail-issue"><div style="font-size:16px;width:28px;text-align:center;flex-shrink:0;">'+s.icon+'</div><div class="detail-issue-text"><strong>'+s.title+'</strong><br>'+s.render(data)+'</div></div>';});return h;}

