(function(){var params=new URLSearchParams(location.search);var challengeId=params.get('challenge');if(!challengeId)return;fetch(API+'/api/scan/'+challengeId+'/challenge').then(function(r){return r.json();}).then(function(d){if(!d.domain||!d.score)return;var banner=document.createElement('div');banner.style.cssText='position:fixed;bottom:0;left:0;right:0;z-index:90;background:linear-gradient(135deg,#141d33,#1a2542);border-top:2px solid var(--accent-gold);padding:16px 24px;display:flex;align-items:center;justify-content:center;gap:16px;flex-wrap:wrap;animation:fadeUp .4s ease-out;';var scoreColor=d.score>=80?'var(--success)':d.score>=60?'var(--info)':d.score>=40?'var(--warning)':'var(--danger)';banner.innerHTML='<div style="display:flex;align-items:center;gap:12px"><div style="width:44px;height:44px;border-radius:10px;background:'+scoreColor+'20;border:2px solid '+scoreColor+';display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:800;color:'+scoreColor+'">'+d.score+'</div><div><div style="font-weight:700;font-size:14px;color:var(--text-primary)">'+d.domain+' scored '+d.score+'/100</div><div style="font-size:12px;color:var(--accent-gold)">Can your website beat it? Paste your URL above and find out!</div></div></div><button onclick="this.parentElement.remove()" style="background:none;border:none;color:var(--text-muted);cursor:pointer;font-size:18px;padding:4px 8px">✕</button>';document.body.appendChild(banner);var heroSub=document.querySelector('.hero-sub');if(heroSub)heroSub.innerHTML='<strong style="color:var(--accent-gold)">'+d.domain+'</strong> scored <strong style="color:'+scoreColor+'">'+d.score+'/100</strong>. Think your site is better? Paste your URL and find out.';if(d.achievements&&d.achievements.length>0){var achDiv=document.createElement('div');achDiv.style.cssText='display:flex;justify-content:center;gap:8px;margin-top:12px;flex-wrap:wrap;';d.achievements.forEach(function(a){achDiv.innerHTML+='<span style="font-size:11px;padding:4px 12px;border-radius:100px;background:'+a.color+'15;color:'+a.color+';border:1px solid '+a.color+'30;font-family:Space Mono,monospace;font-weight:600">'+a.icon+' '+a.title+'</span>';});var auditBox=document.querySelector('.audit-box');if(auditBox)auditBox.appendChild(achDiv);}}).catch(function(){});})();
